INSERT INTO DOI_DEPT_COST (YYYYMM, SEL_CODE, SITE, 코스트센터분류, 코스트센터유형, 계정코드, 계정과목, 비용구분, 차변금액, 대변금액)
SELECT YYYYMM, SEL_CODE, SITE, 코스트센터분류, 코스트센터유형, 계정코드, 계정과목, 비용구분, 차변금액, 대변금액
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYYMM, SITE, 코스트센터, 계정코드) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_ACCT_EXPEN b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SITE = a.SITE
	AND b.코스트센터 = a.코스트센터
	AND b.계정코드 = a.계정코드
);

DROP TABLE #TempTable;

INSERT INTO DOI_DEPT_COST
(
YYYYMM
, SEL_CODE
, SITE
, 코스트센터
, 코스트센터분류
, 코스트센터유형
, 계정코드
, 계정과목
, 비용구분
, 차변금액
, 대변금액
)
VALUES
(
#{yyyymm}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='베트남' then 'VN' else left(#{site},2) end
, #{코스트센터}
, #{코스트센터분류}
, #{코스트센터유형}
, #{계정코드}
, #{계정과목}
, #{비용구분}
, #{차변금액}
, #{대변금액}
);

